--
-- Table structure for table `caipiao_wanfa_old`
--

DROP TABLE IF EXISTS `caipiao_wanfa_old`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `caipiao_wanfa_old` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `title` varchar(60) NOT NULL,
  `typeid` char(30) NOT NULL,
  `playid` char(30) NOT NULL,
  `class1` varchar(20) NOT NULL DEFAULT '' COMMENT 'danh mục1',
  `class2` varchar(20) NOT NULL DEFAULT '' COMMENT 'danh mục2',
  `class3` varchar(20) NOT NULL DEFAULT '' COMMENT 'danh mục3',
  `func` varchar(20) NOT NULL DEFAULT '' COMMENT '',
  `totalzs` int(11) NOT NULL COMMENT 'số cược',
  `rate` decimal(12,2) NOT NULL COMMENT 'tỷ lệ',
  `fandian` decimal(3,1) NOT NULL COMMENT 'hoàn cược',
  `minxf` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT 'thấp nhất',
  `maxxf` decimal(10,2) NOT NULL DEFAULT '10000.00' COMMENT 'tối đasố tiền đặt cược',
  `remark` text NOT NULL,
  `sort` tinyint(3) NOT NULL DEFAULT '0' COMMENT 'Sắp xếp',
  `num` smallint(5) NOT NULL DEFAULT '0' COMMENT '',
  `expect` varchar(20) NOT NULL DEFAULT '' COMMENT 'mở thưởngmã kỳ',
  `isopen` tinyint(1) NOT NULL DEFAULT '1' COMMENT '1bật 0tắt',
  PRIMARY KEY (`id`),
  KEY `typeid` (`typeid`),
  KEY `playid` (`playid`)
) ENGINE=InnoDB AUTO_INCREMENT=357 DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC;
/*!40101 SET character_set_client = @saved_cs_client */;

